<?php
 declare(strict_types=1); namespace League\CommonMark\Normalizer; final class TextNormalizer implements TextNormalizerInterface { private const CASE_FOLD = [ ['µ', 'ſ', "\xCD\x85", 'ς', "\xCF\x90", "\xCF\x91", "\xCF\x95", "\xCF\x96", "\xCF\xB0", "\xCF\xB1", "\xCF\xB5", "\xE1\xBA\x9B", "\xE1\xBE\xBE", "\xC3\x9F", "\xE1\xBA\x9E"], ['μ', 's', 'ι', 'σ', 'β', 'θ', 'φ', 'π', 'κ', 'ρ', 'ε', "\xE1\xB9\xA1", 'ι', 'ss', 'ss'], ]; public function normalize(string $text, $context = null): string { $text = \preg_replace('/\s+/', ' ', \trim($text)); if (!\defined('MB_CASE_FOLD')) { $text = \str_replace(self::CASE_FOLD[0], self::CASE_FOLD[1], $text); return \mb_strtolower($text, 'UTF-8'); } return \mb_convert_case($text, \MB_CASE_FOLD, 'UTF-8'); } } 